const text = $json.text || "";

let parsed;

try {
  const cleaned = text
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  parsed = JSON.parse(cleaned);

} catch (e) {
  parsed = { skills: [] };
}

const skills = parsed.skills || [];

// fallback if no skills found
if (skills.length === 0) {
  return [{
    json: {
      skill: "Microsoft 365"
    }
  }];
}

return skills.map(skill => ({
  json: {
    skill: skill
  }
}));

